module top_module(D,CLK,RSTB,Q,QN);input D;
 input CLK;
 input RSTB;
 output Q;
 output QN;

 reg X_Qtemp;

 always @(posedge CLK or negedge RSTB) begin
   if (~RSTB) begin
     X_Qtemp <= 1'b0;
   end else begin
     X_Qtemp <= D;
   end
 end

 assign QN = ~X_Qtemp;
 assign Q = X_Qtemp;

endmodule
